import java.util.Scanner;

public class SecureBufferUsage {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        System.out.print("Enter your name: ");
        String name = scanner.nextLine();

        // Validate input length before copying to buffer
        if (name.length() > 10) {
            System.out.println("Input exceeds maximum buffer size. Please enter a shorter name.");
            return;
        }

        // Use safe copy to avoid buffer overflow
        byte[] buffer = new byte[10];
        System.arraycopy(name.getBytes(), 0, buffer, 0, Math.min(name.length(), buffer.length));

        System.out.println("Hello, " + new String(buffer));
    }
}

### Explanation:
취약유형: Buffer Overflow
